mapper.select:
SELECT /* base.sy :: SyhBatchHist :: selectList */ h.* , ste.site_nm AS site_nm FROM syh_batch_hist h LEFT JOIN sy_site ste ON ste.site_id = h.site_id
ORDER BY h.batch_hist_id ASC ORDER BY h.batch_hist_id DESC ORDER BY h.batch_nm ASC ORDER BY h.batch_nm DESC ORDER BY h.reg_date ASC ORDER BY h.reg_date DESC ORDER BY h.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

SELECT /* base.sy :: SyhBatchHist :: selectPageList */ h.* , ste.site_nm AS site_nm FROM syh_batch_hist h LEFT JOIN sy_site ste ON ste.site_id = h.site_id
ORDER BY h.batch_hist_id ASC ORDER BY h.batch_hist_id DESC ORDER BY h.batch_nm ASC ORDER BY h.batch_nm DESC ORDER BY h.reg_date ASC ORDER BY h.reg_date DESC ORDER BY h.reg_date DESC
LIMIT #{limit} OFFSET #{offset}
